18	// PreMergeChecksDir is the project-relative directory scanned for check
19	// definitions before each land-back attempt.
20	const PreMergeChecksDir = ".ddx/checks"
21	
22	// PreMergeChecksEvidenceSubdir is the per-attempt subdirectory under the
23	// execution evidence dir into which check result files (one JSON per check)
24	// are written.
25	const PreMergeChecksEvidenceSubdir = "checks"
26	
27	// PreMergeChecksOutcome captures everything callers need to (a) decide
28	// whether to land or preserve and (b) record events on the bead.
29	type PreMergeChecksOutcome struct {
30		// Results is the per-check outcome for every check that actually ran
31		// (post-AppliesTo filter, post-bypass filter). Empty when no checks
32		// applied.
33		Results []checks.Result
34		// Bypassed lists checks_bypass entries that took effect (i.e. matched a
35		// loaded check by name and were honoured for this run). Each entry is
36		// recorded as a `checks-bypass` event by AppendPreMergeChecksEvents.
37		Bypassed []bead.ChecksBypassEntry
38		// Blocked is true when at least one applicable, non-bypassed check
39		// returned status=block or status=error. The caller MUST NOT land the
40		// worker's result when Blocked is true; PreserveAfterPreMergeChecks
41		// performs the canonical preservation + event-record dance.
42		Blocked bool
43		// BlockingNames lists the names of the checks responsible for Blocked=true,
44		// sorted alphabetically for stable ordering in evidence.
45		BlockingNames []string
46		// Reason is a short, human-readable summary suitable for the
47		// ExecuteBeadResult.Reason / land Reason field on a preserved outcome.
48		Reason string
49		// EvidenceDir is the absolute directory where per-check JSON result files
50		// were written (the directory the checks runner used as EVIDENCE_DIR).
51		EvidenceDir string
52	}
53	
54	// RunPreMergeChecks loads all .ddx/checks/*.yaml definitions for the project,
55	// filters by AppliesTo against the bead's labels and the changed-paths set
56	// computed from base..result, removes any checks named in the bead's
57	// checks_bypass annotation, and runs the rest in parallel via checks.Run.
58	//
59	// The bead's checks_bypass annotation is validated up front via
60	// bead.ChecksBypasses; any malformed entry (missing reason, etc.) returns a
61	// non-nil error so the caller can preserve loudly instead of silently
62	// honouring an invalid bypass.
63	//
64	// evidenceDir is the absolute path to the per-attempt execution evidence
65	// directory (typically <projectRoot>/.ddx/executions/<run-id>/). Check result
66	// files are written under evidenceDir/checks/. The directory is created if it
67	// does not exist.
68	//
69	// When the project has no .ddx/checks/ directory or no applicable checks,
70	// the returned outcome has Blocked=false and empty Results — the caller
71	// should proceed with the land as if no gate were configured.
72	func RunPreMergeChecks(ctx context.Context, projectRoot string, b *bead.Bead, baseRev, resultRev, evidenceDir string) (*PreMergeChecksOutcome, error) {
73		if projectRoot == "" {
74			return nil, fmt.Errorf("pre-merge checks: project_root required")
75		}
76		if b == nil {
77			return nil, fmt.Errorf("pre-merge checks: bead required")
78		}
79	
80		bypasses, err := bead.ChecksBypasses(b)
81		if err != nil {
82			return nil, fmt.Errorf("pre-merge checks: invalid checks_bypass annotation: %w", err)
83		}
84	
85		all, err := checks.LoadDir(filepath.Join(projectRoot, PreMergeChecksDir))
86		if err != nil {
87			return nil, fmt.Errorf("pre-merge checks: load: %w", err)
88		}
89		if len(all) == 0 {
90			return &PreMergeChecksOutcome{}, nil
91		}
92	
93		bypassByName := make(map[string]bead.ChecksBypassEntry, len(bypasses))
94		for _, e := range bypasses {
95			bypassByName[e.Name] = e
96		}
97	
98		var toRun []checks.Check
99		var honouredBypass []bead.ChecksBypassEntry
100		for _, c := range all {
101			if e, ok := bypassByName[c.Name]; ok {
102				honouredBypass = append(honouredBypass, e)
103				continue
104			}
105			toRun = append(toRun, c)
106		}
107	
108		changed, err := preMergeChangedPaths(projectRoot, baseRev, resultRev)
109		if err != nil {
110			return nil, fmt.Errorf("pre-merge checks: diff base..result: %w", err)
111		}
112	
113		checksEvidence := filepath.Join(evidenceDir, PreMergeChecksEvidenceSubdir)
114		ictx := checks.InvocationContext{
115			BeadID:       b.ID,
116			DiffBase:     baseRev,
117			DiffHead:     resultRev,
118			ProjectRoot:  projectRoot,
119			EvidenceDir:  checksEvidence,
120			RunID:        newPreMergeRunID(),
121			BeadLabels:   b.Labels,
122			ChangedPaths: changed,
123		}
124	
125		results, err := checks.Run(ctx, toRun, ictx)
126		if err != nil {
127			return nil, fmt.Errorf("pre-merge checks: run: %w", err)
128		}
129	
130		outcome := &PreMergeChecksOutcome{
131			Results:     results,
132			Bypassed:    honouredBypass,
133			EvidenceDir: checksEvidence,
134		}
135		for _, r := range results {
136			if r.Status == checks.StatusBlock || r.Status == checks.StatusError {
137				outcome.Blocked = true
138				outcome.BlockingNames = append(outcome.BlockingNames, r.Name)
139			}
140		}
141		if outcome.Blocked {
142			sort.Strings(outcome.BlockingNames)
143			outcome.Reason = fmt.Sprintf("pre-merge checks blocked: %s", strings.Join(outcome.BlockingNames, ", "))
144		}
145		return outcome, nil
146	}
147	
148	// PreMergeChecksReason is the canonical Reason prefix written onto preserved
149	// landings whose preservation was triggered by the pre-merge checks gate.
150	// Callers (status classifiers, dashboards) match on this prefix to bucket
151	// pre-merge-checks misses apart from generic merge conflicts or gate failures.
152	const PreMergeChecksReason = "pre-merge checks blocked"
153	
154	// AppendPreMergeChecksEvents records one bead event per honoured bypass
155	// (kind=checks-bypass) and, when blocked, one event per blocking check
156	// (kind=checks-blocked). Best-effort: append failures are returned as the
157	// first error encountered so callers can decide whether to surface or log.
158	//
159	// actor and source are forwarded onto every appended event so the audit
160	// trail attributes the gate decision to the right worker / loop session.
161	func AppendPreMergeChecksEvents(store BeadEventAppender, beadID string, outcome *PreMergeChecksOutcome, actor, source string, now time.Time) error {
162		if store == nil || outcome == nil {
163			return nil
164		}
165		var firstErr error
166		for _, e := range outcome.Bypassed {
167			body := fmt.Sprintf("name=%s\nreason=%s", e.Name, e.Reason)
168			if e.Bead != "" {
169				body += "\nbead=" + e.Bead
170			}
171			ev := bead.BeadEvent{
172				Kind:      "checks-bypass",
173				Summary:   fmt.Sprintf("pre-merge check %q bypassed", e.Name),
174				Body:      body,
175				Actor:     actor,
176				Source:    source,
177				CreatedAt: now,
178			}
179			if err := store.AppendEvent(beadID, ev); err != nil && firstErr == nil {
180				firstErr = err
181			}
182		}
183		if outcome.Blocked {
184			for _, r := range outcome.Results {
185				if r.Status != checks.StatusBlock && r.Status != checks.StatusError {
186					continue
187				}
188				body := fmt.Sprintf("name=%s\nstatus=%s", r.Name, r.Status)
189				if r.Message != "" {
190					body += "\nmessage=" + r.Message
191				}
192				ev := bead.BeadEvent{
193					Kind:      "checks-blocked",
194					Summary:   fmt.Sprintf("pre-merge check %q returned %s", r.Name, r.Status),
195					Body:      body,
196					Actor:     actor,
197					Source:    source,
198					CreatedAt: now,
199				}
200				if err := store.AppendEvent(beadID, ev); err != nil && firstErr == nil {
201					firstErr = err
202				}
203			}
204		}
205		return firstErr
206	}
207	
208	// PreserveAfterPreMergeChecks is the canonical preservation step invoked when
209	// RunPreMergeChecks returned Blocked=true. It writes refs/ddx/iterations/...
210	// pointing at the worker's resultRev (so the work survives for later
211	// inspection) and returns the synthetic LandResult{Status:"preserved"} that
212	// callers can hand to ApplyLandResultToExecuteBeadResult.
213	//
214	// The preserved iteration ref naming follows the existing
215	// landIterationRef convention so operators see a single ref namespace
216	// regardless of which gate triggered the preservation.
217	func PreserveAfterPreMergeChecks(projectRoot string, res *ExecuteBeadResult, outcome *PreMergeChecksOutcome, gitOps OrchestratorGitOps) (*LandResult, error) {
218		if outcome == nil || !outcome.Blocked {
219			return nil, fmt.Errorf("pre-merge checks: preserve called without blocked outcome")
220		}
221		if gitOps == nil {
222			gitOps = &RealOrchestratorGitOps{}
223		}
224		ref := PreserveRef(res.BeadID, res.BaseRev)
225		if err := gitOps.UpdateRef(projectRoot, ref, res.ResultRev); err != nil {
226			return nil, fmt.Errorf("pre-merge checks: preserving %s: %w", ref, err)
227		}
228		return &LandResult{
229			Status:      "preserved",
230			PreserveRef: ref,
231			Reason:      outcome.Reason,
232		}, nil
233	}
234	
235	// preMergeChangedPaths returns the list of paths changed between baseRev and
236	// resultRev as reported by `git diff --name-only`. Returns (nil, nil) when
237	// either rev is empty (e.g. a no-changes attempt that should not exercise the
238	// path-glob filters at all).
239	func preMergeChangedPaths(projectRoot, baseRev, resultRev string) ([]string, error) {
240		if baseRev == "" || resultRev == "" || baseRev == resultRev {
241			return nil, nil
242		}
243		out, err := internalgit.Command(context.Background(), projectRoot, "diff", "--name-only", baseRev, resultRev).CombinedOutput()
244		if err != nil {
245			return nil, fmt.Errorf("git diff --name-only %s %s: %s: %w", baseRev, resultRev, strings.TrimSpace(string(out)), err)
246		}
247		var paths []string
248		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
249			if p := strings.TrimSpace(line); p != "" {
250				paths = append(paths, p)
251			}
252		}
253		return paths, nil
254	}
255	
256	func newPreMergeRunID() string {
257		var b [4]byte
258		_, _ = rand.Read(b[:])
259		return time.Now().UTC().Format("20060102T150405") + "-" + hex.EncodeToString(b[:])
260	}
