3	// checks_premerge_e2e_test.go — end-to-end coverage for the pre-merge checks
4	// gate wired into the execute-bead loop's land-back step.
5	//
6	// Each test boots a real temp git repo + .ddx tracker store, drops a fixture
7	// .ddx/checks/dummy-fail.yaml whose script always returns status=block, and
8	// drives SubmitWithPreMergeChecks against a synthesised worker
9	// ExecuteBeadResult to assert the documented contract:
10	//
11	//	Test 1 — block fixture causes preserve, submit not called, evidence and
12	//	         events recorded.
13	//	Test 2 — block fixture + checks_bypass annotation causes submit to run
14	//	         and a checks-bypass event to be recorded.
15	
16	import (
17		"context"
18		"os"
19		"os/exec"
20		"path/filepath"
21		"strings"
22		"testing"
23		"time"
24	
25		"github.com/DocumentDrivenDX/ddx/internal/bead"
26	)
27	
28	// preMergeRepo is a focused version of landTestRepo specialised for these
29	// pre-merge gate tests: it owns a .ddx tracker store as well as the git repo,
30	// so we can create beads and read events without any extra setup.
31	type preMergeRepo struct {
32		t       *testing.T
33		dir     string
34		store   *bead.Store
35		baseSHA string
36	}
37	
38	func newPreMergeRepo(t *testing.T) *preMergeRepo {
39		t.Helper()
40		dir := t.TempDir()
41		r := &preMergeRepo{t: t, dir: dir}
42		r.runGit("init", "-b", "main")
43		r.runGit("config", "user.name", "Test")
44		r.runGit("config", "user.email", "test@test.local")
45		if err := os.WriteFile(filepath.Join(dir, "README.md"), []byte("# pre-merge\n"), 0o644); err != nil {
46			t.Fatal(err)
47		}
48		r.runGit("add", "-A")
49		r.runGit("commit", "-m", "init")
50		r.baseSHA = strings.TrimSpace(r.runGit("rev-parse", "HEAD"))
51	
52		r.store = bead.NewStore(filepath.Join(dir, ".ddx"))
53		if err := r.store.Init(); err != nil {
54			t.Fatalf("store init: %v", err)
55		}
56		return r
57	}
58	
59	func (r *preMergeRepo) runGit(args ...string) string {
60		r.t.Helper()
61		cmd := exec.Command("git", append([]string{"-C", r.dir}, args...)...)
62		out, err := cmd.CombinedOutput()
63		if err != nil {
64			r.t.Fatalf("git %s: %s: %v", strings.Join(args, " "), string(out), err)
65		}
66		return string(out)
67	}
68	
69	// commitNoOp creates a one-file commit reachable via the object store but not
70	// any branch, returning its SHA. Used as the worker's resultRev so the gate
71	// has a real (baseRev → resultRev) range to diff against.
72	func (r *preMergeRepo) commitNoOp() string {
73		r.t.Helper()
74		wt, err := os.MkdirTemp("", "premerge-wt-*")
75		if err != nil {
76			r.t.Fatal(err)
77		}
78		_ = os.RemoveAll(wt)
79		r.runGit("worktree", "add", "--detach", wt, r.baseSHA)
80		defer func() {
81			r.runGit("worktree", "remove", "--force", wt)
82			_ = os.RemoveAll(wt)
83		}()
84		if err := os.WriteFile(filepath.Join(wt, "noop.txt"), []byte("hello\n"), 0o644); err != nil {
85			r.t.Fatal(err)
86		}
87		cmd := exec.Command("git", "-C", wt, "add", "-A")
88		if out, err := cmd.CombinedOutput(); err != nil {
89			r.t.Fatalf("git add: %s: %v", string(out), err)
90		}
91		cmd = exec.Command("git", "-C", wt,
92			"-c", "user.name=Test", "-c", "user.email=test@test.local",
93			"commit", "-m", "noop")
94		if out, err := cmd.CombinedOutput(); err != nil {
95			r.t.Fatalf("git commit: %s: %v", string(out), err)
96		}
97		cmd = exec.Command("git", "-C", wt, "rev-parse", "HEAD")
98		out, err := cmd.CombinedOutput()
99		if err != nil {
100			r.t.Fatalf("git rev-parse: %s: %v", string(out), err)
101		}
102		return strings.TrimSpace(string(out))
103	}
104	
105	// writeDummyFailCheck drops a deterministic check definition that always
106	// writes status=block and exits 0 (so the runner's failure mode is "result
107	// file says block", not "command crashed").
108	func (r *preMergeRepo) writeDummyFailCheck() {
109		r.t.Helper()
110		checkDir := filepath.Join(r.dir, ".ddx", "checks")
111		if err := os.MkdirAll(checkDir, 0o755); err != nil {
112			r.t.Fatal(err)
113		}
114		yaml := `name: dummy-fail
115	when: pre_merge
116	command: |
117	  cat > "${EVIDENCE_DIR}/${CHECK_NAME}.json" <<EOF
118	  {"status":"block","message":"dummy-fail fixture: always blocks"}
119	  EOF
120	`
121		if err := os.WriteFile(filepath.Join(checkDir, "dummy-fail.yaml"), []byte(yaml), 0o644); err != nil {
122			r.t.Fatal(err)
123		}
124	}
125	
126	// makeBead creates an open bead in the tracker and returns it. extra is
127	// merged into bead.Extra so callers can attach a checks_bypass annotation.
128	func (r *preMergeRepo) makeBead(id string, extra map[string]any) *bead.Bead {
129		r.t.Helper()
130		b := &bead.Bead{
131			ID:     id,
132			Title:  "fixture bead for pre-merge checks",
133			Status: bead.StatusOpen,
134			Labels: []string{"phase:2", "area:checks"},
135			Extra:  extra,
136		}
137		if err := r.store.Create(b); err != nil {
138			r.t.Fatalf("create bead: %v", err)
139		}
140		got, err := r.store.Get(id)
141		if err != nil {
142			r.t.Fatalf("get bead: %v", err)
143		}
144		return got
145	}
146	
147	// readEvents reads the bead's appended events via the store's Events helper.
148	func (r *preMergeRepo) readEvents(id string) []bead.BeadEvent {
149		r.t.Helper()
150		evs, err := r.store.Events(id)
151		if err != nil {
152			r.t.Fatalf("read events: %v", err)
153		}
154		return evs
155	}
156	
157	// TestSubmitWithPreMergeChecks_DummyFailAbortsMerge covers AC #4: a fixture
158	// dummy-fail check causes merge abort, the worker's resultRev is preserved
159	// under refs/ddx/iterations/, the per-check evidence file is on disk, and a
160	// checks-blocked event is appended to the bead.
161	func TestSubmitWithPreMergeChecks_DummyFailAbortsMerge(t *testing.T) {
162		r := newPreMergeRepo(t)
163		r.writeDummyFailCheck()
164		b := r.makeBead("pmc-block-001", nil)
165		resultSHA := r.commitNoOp()
166	
167		runID := time.Now().UTC().Format("20060102T150405") + "-pmcblk1"
168		res := &ExecuteBeadResult{
169			BeadID:       b.ID,
170			BaseRev:      r.baseSHA,
171			ResultRev:    resultSHA,
172			ExecutionDir: filepath.Join(".ddx", "executions", runID),
173		}
174	
175		submitCalled := false
176		submit := func(req LandRequest) (*LandResult, error) {
177			submitCalled = true
178			return &LandResult{Status: "landed", NewTip: req.ResultRev}, nil
179		}
180	
181		land, outcome, err := SubmitWithPreMergeChecks(
182			context.Background(), r.dir, b, res,
183			submit, r.store, "ddx-test-actor", "test-source", nil,
184		)
185		if err != nil {
186			t.Fatalf("SubmitWithPreMergeChecks: %v", err)
187		}
188		if submitCalled {
189			t.Fatalf("submit must NOT be called when pre-merge checks block (AC #4)")
190		}
191		if outcome == nil || !outcome.Blocked {
192			t.Fatalf("outcome must report Blocked=true; got %+v", outcome)
193		}
194		if !sliceContains(outcome.BlockingNames, "dummy-fail") {
195			t.Fatalf("BlockingNames must contain dummy-fail; got %v", outcome.BlockingNames)
196		}
197		if land == nil || land.Status != "preserved" {
198			t.Fatalf("LandResult must be preserved; got %+v", land)
199		}
200		if land.PreserveRef == "" || !strings.HasPrefix(land.PreserveRef, "refs/ddx/iterations/"+b.ID+"/") {
201			t.Fatalf("PreserveRef must follow refs/ddx/iterations/<bead-id>/ convention; got %q", land.PreserveRef)
202		}
203	
204		// Worktree-preservation invariant (AC #2 + #6): the preserve ref must
205		// resolve to the worker's resultSHA in the real git object store.
206		got := strings.TrimSpace(r.runGit("rev-parse", land.PreserveRef))
207		if got != resultSHA {
208			t.Fatalf("preserve ref resolves to %s; want resultSHA %s", got, resultSHA)
209		}
210	
211		// Evidence file (AC #6): checks runner must have written a JSON result
212		// file at <projectRoot>/<execDir>/checks/dummy-fail.json.
213		evidenceFile := filepath.Join(r.dir, res.ExecutionDir, "checks", "dummy-fail.json")
214		data, readErr := os.ReadFile(evidenceFile)
215		if readErr != nil {
216			t.Fatalf("evidence file missing at %s: %v", evidenceFile, readErr)
217		}
218		if !strings.Contains(string(data), `"status":"block"`) {
219			t.Fatalf("evidence file does not show status=block: %s", string(data))
220		}
221	
222		// Event recorded (AC #4): one checks-blocked event for dummy-fail.
223		evs := r.readEvents(b.ID)
224		var blockedEvents []bead.BeadEvent
225		for _, e := range evs {
226			if e.Kind == "checks-blocked" {
227				blockedEvents = append(blockedEvents, e)
228			}
229		}
230		if len(blockedEvents) != 1 {
231			t.Fatalf("expected exactly one checks-blocked event; got %d (events=%+v)", len(blockedEvents), evs)
232		}
233		if !strings.Contains(blockedEvents[0].Body, "name=dummy-fail") {
234			t.Fatalf("checks-blocked event body should name dummy-fail; got %q", blockedEvents[0].Body)
235		}
236	}
