238	// TestSubmitWithPreMergeChecks_BypassAllowsMerge covers AC #5: the same
239	// fixture + a checks_bypass annotation skips the named check, submit runs
240	// normally, and a checks-bypass event with the documented reason is recorded.
241	func TestSubmitWithPreMergeChecks_BypassAllowsMerge(t *testing.T) {
242		r := newPreMergeRepo(t)
243		r.writeDummyFailCheck()
244		b := r.makeBead("pmc-bypass-001", map[string]any{
245			"checks_bypass": []any{
246				map[string]any{
247					"name":   "dummy-fail",
248					"reason": "fixture: dummy-fail is always-block by design; bypassed in this test scenario",
249					"bead":   "pmc-bypass-001",
250				},
251			},
252		})
253		resultSHA := r.commitNoOp()
254	
255		runID := time.Now().UTC().Format("20060102T150405") + "-pmcbyp1"
256		res := &ExecuteBeadResult{
257			BeadID:       b.ID,
258			BaseRev:      r.baseSHA,
259			ResultRev:    resultSHA,
260			ExecutionDir: filepath.Join(".ddx", "executions", runID),
261		}
262	
263		submitCalled := false
264		submit := func(req LandRequest) (*LandResult, error) {
265			submitCalled = true
266			if req.BeadID != b.ID {
267				t.Fatalf("submit got unexpected bead %q; want %q", req.BeadID, b.ID)
268			}
269			return &LandResult{Status: "landed", NewTip: req.ResultRev}, nil
270		}
271	
272		land, outcome, err := SubmitWithPreMergeChecks(
273			context.Background(), r.dir, b, res,
274			submit, r.store, "ddx-test-actor", "test-source", nil,
275		)
276		if err != nil {
277			t.Fatalf("SubmitWithPreMergeChecks: %v", err)
278		}
279		if !submitCalled {
280			t.Fatalf("submit MUST be called when the only blocking check is bypassed (AC #5)")
281		}
282		if outcome == nil {
283			t.Fatalf("outcome required, got nil")
284		}
285		if outcome.Blocked {
286			t.Fatalf("outcome must not be Blocked when only check is bypassed; got %+v", outcome)
287		}
288		if len(outcome.Bypassed) != 1 || outcome.Bypassed[0].Name != "dummy-fail" {
289			t.Fatalf("Bypassed slice must record dummy-fail; got %+v", outcome.Bypassed)
290		}
291		if land == nil || land.Status != "landed" {
